draw ("$r$", O -- P, blue); //radius
markangle("$\theta$", radius=15, (r,0),O,P,blue+0.75bp,arrow=Arrow(2mm)); // theta measured counterclockwise from positive x-axis

//rectangular coordinates
draw ("$y$", A--P); //altitude
label("$x$", (O+A)/2, S);

//end
