import graph;

real y_max = 1;
real y_min = -1;
real x_min = -2;
real x_max = 2;


real x_range = x_max - x_min;
real y_range = y_max - y_min;

real x_mid = (x_min + x_max)/2;
real y_mid = (y_min + y_max)/2;

real Fa(real x){return 1;}
real Fb(real x){return x/2;}
real Fc(real x){return x^2/4;}
real Fd(real x){return x^3/2^3;}
real Fe(real x){return x^4/2^4;}
real Ff(real x){return x^5/2^5;}

picture pic;

picture axes;
currentpicture = axes;
draw(box((x_min,y_min),(x_max,y_max)));
label("$0$",(0,y_min),S);
label("$0$",(x_min,0),W);
draw((0,y_min)--(0,y_max), dotted);
draw((x_min,0)--(x_max,0), dotted);
label(rotate(90)*"$y$",(x_min-x_range/10,y_mid),W);
label("$x$",(x_mid,y_min-y_range/10),S);

picture graph1;
currentpicture = graph1;
add(axes);
draw(graph(Fa,x_min,x_max),blue+linewidth(1.5pt));
label("(a)",(x_mid,y_min-y_range/5),S);

picture graph2;
currentpicture = graph2;
add(axes);
draw(graph(Fb,x_min,x_max),blue+linewidth(1.5pt));
label("(b)",(x_mid,y_min-y_range/5),S);

picture graph3;
currentpicture = graph3;
add(axes);
draw(graph(Fc,x_min,x_max),blue+linewidth(1.5pt));
label("(c)",(x_mid,y_min-y_range/5),S);

picture graph4;
currentpicture = graph4;
add(axes);
draw(graph(Fd,x_min,x_max),blue+linewidth(1.5pt));
label("(d)",(x_mid,y_min-y_range/5),S);

picture graph5;
currentpicture = graph5;
add(axes);
draw(graph(Fe,x_min,x_max),blue+linewidth(1.5pt));
label("(e)",(x_mid,y_min-y_range/5),S);

picture graph6;
currentpicture = graph6;
add(axes);
draw(graph(Ff,x_min,x_max),blue+linewidth(1.5pt));
label("(f)",(x_mid,y_min-y_range/5),S);


currentpicture = pic;
unitsize(2cm);
add(graph1);

add(shift(x_range*1.5,0)*graph2);
add(shift(x_range*1.5*0,-1.5*y_range)*graph3);
add(shift(x_range*1.5,-1.5*y_range)*graph4);
add(shift(x_range*1.5*0,-1.5*y_range*2)*graph5);
add(shift(x_range*1.5*1,-1.5*y_range*2)*graph6);

// Fill in the energies you want in line 8. For example, for 3 J kinetic energy, 4 J potential energy, and 0 J thermal energy, change "{1, 0, 0}" to "{3, 4, 0}" in line 8
// Then hit "RENDER AS IMAGE" and right click to download your chart
// There are various other features if you want to customize things

//-----------------  DATA TO PLOT ---------------

real[] energies = {1, 0}; //you can make this as many types of energy as you want, but update line 9 as well
string[] energy_types = {"Chemical", "Thermal"};
string unit = ""; //symbol for energy units, delete the J (but leave the quotes) for no units

string title = "Energy Bar Chart";

//----------------- TURN THINGS ON AND OFF --------------

bool show_total = false; //add auto-calculated "total energy" bar at the end

bool show_values_for_energies = false; //writes out the energy above each column

bool show_ticks = true; // whether or not to show ticks on $y$ axis
bool show_scale = false; // whether or not to show labels on $y$ axis; draws ticks even if "show_ticks" is false
bool show_y_label = false; //whether to write "Energy (J)" or similar on y-axis

bool show_title = false;

//-----------------  AESTHETIC TWEAKS --------------------

//attempts to mimic "Energy Skate Park" by default
//https://phet.colorado.edu/sims/html/energy-skate-park/latest/energy-skate-park_en.html

//size of image in cm
real width = 6;
real height = 8;

//column colors
//reference: https://asymptote.sourceforge.io/doc/Pens.html
pen[] colors = {heavygreen, royalblue*.85, .7*orange+ .3*red, olive*1.3}; 

//style of labels for the columns
//reference: https://asymptote.sourceforge.io/doc/Pens.html
pen labels = Helvetica();

// increase to make bars wider
real bar_width = 0.55;

// ---------------  BELOW HERE YOU USUALLY DON'T NEED TO CHANGE THINGS ------------

import graph;

unit = "$\mathrm{" + unit + "}$";

size(width*72/2.54, height*72/2.54, IgnoreAspect);

energies.cyclic = true; //allows getting last energy with [-1] index
colors.cyclic = true; //allows recycling if too few colors given

if(energies.length != energy_types.length){
label("energies and energy types aren't the same length");
}

if(show_total){
energies.push(sum(energies));
energy_types.push("Total");
}

int num_energies = energies.length;

bar_width = 1/num_energies * bar_width;

real max_energy = 1;


ticks yticks = RightTicks(format = "%");
if(! show_ticks){ yticks = NoTicks;}
if(show_scale){ yticks = RightTicks();}

string ylabel = "";
if(show_y_label){
	if(unit == "$\mathrm{}$" || unit == "$\mathrm{ }$"){
		ylabel = "Energy";
	}
else{
	ylabel = "Energy \,\,(" + unit+")";
	}
}



// -----------------  DO THE ACTUAL DRAWING   --------------------

for(int i = 0; i< num_energies; ++i){
	// bars
	filldraw(shift(bar_width/2,0)*shift(i/num_energies,0)*box((0,0),(bar_width,energies[i])), colors[i] );

    //labels
    label(rotate(90)*energy_types[i],(bar_width/2 + i/num_energies + bar_width/2,0),S, labels);

    if (show_values_for_energies){
    	label(string(energies[i])+"\;"+unit,(bar_width + i/num_energies,max(0,energies[i])),N);
		}
}

xaxis(0, 1);
yaxis(0, max_energy, L = ylabel, ticks = yticks);

if(show_title){label(title, (.5,max_energy*1.15),N);}

