//"weight" is between zero and 1 and how many rotations around the red needle should point
//top center of scale is (0,0); bottom center is (0,-1)
picture scales(real weight){
	picture sc;
	pen scpen = linewidth(2pt);

    draw(sc,unitcircle,scpen);

	int ticks = 8;
	for(int i = 0; i<ticks; ++i){
		real theta = 360*i/ticks;
		draw(sc,.8*dir(theta)--dir(theta),scpen);
	}

    draw(sc,scale(.6)*((0,0)--dir(90-weight*360)), red+linewidth(2pt));

    real cut_theta = 15;
    draw(sc,(-1.7,-1.4)--(1.7,-1.4)--(1.7,0)--arc((0,0),1.7,0,90-cut_theta)--arc((0,0),1.7,90+cut_theta,180)--cycle,scpen);

	pair top_right = 1.7*dir(90-cut_theta);
    pair top_left = 1.7*dir(90+cut_theta);

	real neck_height = 0.3;

    draw(sc,shift(top_right)*((0,0)--(0,neck_height)), linewidth(2pt));
    draw(sc,shift(top_left)*((0,0)--(0,neck_height)), linewidth(2pt));

    real pan_bot = neck_height + top_right.y;
    real pan_height = 0.4;


    draw(sc, (-1.6,pan_bot)--(1.6,pan_bot)--arc((1.6,pan_bot+pan_height),pan_height,-90,0)--arc((-1.6,pan_bot+pan_height),pan_height,180,270),scpen);


real tot_height = (1.4+pan_bot+pan_height);
return shift(0,-(pan_bot+pan_height)/tot_height)*scale(1/tot_height)*sc;
}

add(scales(0));

//accepts an angle for the hand from vertical. clock(0) is noon. clock(90) is 3:00, etc.

picture clock(real t){
picture lc;
draw(lc, scale(.25)*unitcircle);
draw(lc, scale(.25)*rotate(- t)*((0,0)--(0,1)));
return scale(.6)*lc;
}

add(clock(30));

// Draw the hands

int hour = 3; 
int minute = 53;

pair hHand = 0.4*expi(pi/2 - hour*pi/6 - minute*pi/360);
pair mHand = 0.7*expi(pi/2 - 2*pi*minute/60);

dot(origin);
draw(origin--hHand);
draw(origin--mHand);

// Draw the rest of the clock

draw(unitcircle);

pair[] hourmarks = {};
pair[] minmarks = {};

for (int hr = 0; hr < 12; ++hr){
 hourmarks.push(expi(pi/2 - hr*pi/6));
 draw(hourmarks[hr]--0.9*hourmarks[hr]);
 if (hr == 0){
  label(string(12),0.8*hourmarks[hr]);
 }
 else {
  label(string(hr),0.8*hourmarks[hr]);
 }
}

for (int min = 0; min < 60; ++min){
 minmarks.push(expi(pi/2 - min*pi/30));
 draw(minmarks[min]--0.95*minmarks[min]);
}

// Draw arrow

real arcRadius = 0.5;
real arcMeasure = 120;
bool clockwise = true; //determines which direction the arrow points
real arrowStart; real arrowEnd;

if (clockwise){
 arrowStart = degrees(pi/2 - 2*pi*minute/60) - 5;
 arrowEnd = arrowStart - arcMeasure;
 label("CW", 0.6*arcRadius*dir((arrowStart+arrowEnd)/2), gray(0.7));
}
