path lens(real h, real r){
real dist = sqrt(r^2 - h^2/4);
real theta = asin(h/(2*r));
real theta_deg = theta * 180/pi;
path len = arc((dist,0),r,180+theta_deg,180-theta_deg);
len = len--rotate(180)*len;
return len;
}

